#include<bits/stdc++.h>
using namespace std;
int v[1001];
int main() {
	int n;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		char c;
		cin>>c;
		if(c=='p'){
			v[i+1]++;
		}else{
			v[i-1]++;
		}
	}
	int ant[3]={0};
	for(int i=1;i<=n;i++) ant[v[i]]++;
	cout<<ant[0]<<" "<<ant[1]<<" "<<ant[2];
	return 0;
}
